{
  "domain_analysis": {
    "business_context": "A logistics platform introducing automated route optimization for drivers at shift start, with dynamic recalculation triggers, customer notification windows, vehicle class constraints, and configurable stop duration. This spans multiple bounded contexts: route planning, fleet/driver management, delivery lifecycle, and customer notifications.",
    "bounded_context": "Multiple contexts identified: (1) Route Planning — owns route calculation, optimization, recalculation triggers, stop ordering, and ETA computation. (2) Fleet Management — owns driver profiles, shift lifecycle, vehicle class licensing, and zone assignments. (3) Delivery Management — owns delivery lifecycle (pending, in-transit, failed, completed), zone classification, and package attributes (size/weight/class). (4) Customer Notification — owns notification rules, delivery proximity windows, and communication channels. Each context has its own language and should communicate via domain events, not direct coupling.",
    "ubiquitous_language": [
      { "term": "Shift", "definition": "A bounded work period for a driver, beginning when they clock in and ending when they clock out or complete all assigned deliveries. A shift is the trigger for initial route assignment." },
      { "term": "Optimized Route", "definition": "An ordered sequence of delivery stops calculated to minimize total travel time/distance for a driver within their zone, respecting vehicle class constraints." },
      { "term": "Zone", "definition": "A geographic area that groups deliveries and drivers. A driver is assigned to exactly one zone per shift. Deliveries belong to a zone based on their destination address." },
      { "term": "Pending Delivery", "definition": "A delivery that has been created and assigned to a zone but not yet assigned to a driver's route or attempted." },
      { "term": "Failed Delivery", "definition": "A delivery that was attempted but could not be completed (e.g., recipient unavailable, access denied). Triggers route recalculation to remove or reschedule the stop." },
      { "term": "Vehicle Class", "definition": "A classification of the vehicle a driver is licensed to operate (e.g., motorcycle, van, truck, freight). Determines which deliveries are eligible for assignment based on package requirements." },
      { "term": "Licensed Vehicle Class", "definition": "The vehicle class(es) a driver holds valid credentials to operate. This is a property of the driver, not the vehicle, and constrains delivery assignment." },
      { "term": "Route Deviation", "definition": "When a driver's actual GPS position or stop sequence diverges from the suggested optimized route, triggering recalculation." },
      { "term": "Next 3 Stops Window", "definition": "A proximity threshold defined as the 3 upcoming stops in the driver's current route sequence. Entering this window triggers customer notification for the relevant delivery." },
      { "term": "Estimated Stop Duration", "definition": "The time budgeted for a driver to complete a single delivery stop. Defaults to 4 minutes but is overridable per zone by the operations team." },
      { "term": "Recalculation Trigger", "definition": "An event that invalidates the current optimized route and requires a new route to be computed. Three defined triggers: new delivery added to zone, delivery marked failed, driver deviation." },
      { "term": "Delivery-Vehicle Compatibility", "definition": "The rule that a delivery's physical requirements (size, weight, type) must be satisfiable by the driver's licensed vehicle class. This is a hard constraint, not an optimization preference." }
    ]
  },

  "business_rules": [
    {
      "id": "BR-1",
      "rule": "A driver MUST be assigned an optimized route automatically when they start their shift, based on all pending deliveries in their assigned zone at that moment.",
      "invariant": false,
      "invariant_justification": "This is an operational policy about when route assignment occurs. The business could decide to allow manual route building or deferred assignment. The system would not be corrupt without it — just less efficient.",
      "testable_assertion": "When a driver starts a shift in zone Z, the system produces a route containing all pending deliveries in zone Z that are compatible with the driver's vehicle class, ordered by optimization algorithm."
    },
    {
      "id": "BR-2",
      "rule": "A driver MUST NOT be assigned a delivery that requires a vehicle class they are not licensed for.",
      "invariant": true,
      "invariant_justification": "This is a physical and legal constraint. A motorcycle cannot carry freight. Violating this creates safety hazards, regulatory violations, and guaranteed delivery failures. If the system assigns an incompatible delivery, the data is corrupt.",
      "testable_assertion": "For every delivery D on driver X's route: D.requiredVehicleClass is within X.licensedVehicleClasses. No exceptions."
    },
    {
      "id": "BR-3",
      "rule": "The route MUST be recalculated when a new pending delivery is added to the driver's active zone.",
      "invariant": false,
      "invariant_justification": "This is an optimization policy. The business could choose to batch recalculations or defer them. The system is not corrupt if a new delivery waits until next recalculation window — it's just suboptimal.",
      "testable_assertion": "Given driver X has an active route in zone Z, when a new delivery is created in zone Z, then the route optimization service recalculates driver X's route to include the new delivery (if vehicle-class compatible)."
    },
    {
      "id": "BR-4",
      "rule": "The route MUST be recalculated when a delivery on the route is marked as failed.",
      "invariant": false,
      "invariant_justification": "Operational efficiency policy. A stale route with a failed stop is suboptimal but not a data integrity violation.",
      "testable_assertion": "Given driver X has delivery D on their route, when D is marked as failed, then the route is recalculated excluding D and re-optimizing the remaining stops."
    },
    {
      "id": "BR-5",
      "rule": "The route MUST be recalculated when the driver manually deviates from the suggested route.",
      "invariant": false,
      "invariant_justification": "Operational policy to keep the route useful after deviation. The system is not corrupt if recalculation is delayed — the driver simply continues off-route.",
      "testable_assertion": "Given driver X deviates from the suggested route (visits stops out of order or moves away from next suggested stop beyond a threshold), then the system recalculates the route from the driver's current position."
    },
    {
      "id": "BR-6",
      "rule": "A customer MUST be notified when their delivery enters the 'next 3 stops' window of the driver's route.",
      "invariant": false,
      "invariant_justification": "Customer communication policy. The notification threshold (3 stops) is a business preference that could be changed to 2 or 5 stops. Missing a notification is a UX failure, not a data corruption.",
      "testable_assertion": "When delivery D moves into position 1, 2, or 3 in the driver's ordered route, the customer associated with D receives a notification. The notification is sent exactly once per delivery per entry into the window."
    },
    {
      "id": "BR-7",
      "rule": "The default estimated stop duration is 4 minutes. The operations team can override this value per zone.",
      "invariant": false,
      "invariant_justification": "A configurable operational parameter. The default and the override mechanism are business preferences, not system integrity constraints.",
      "testable_assertion": "Route ETA calculations use 4 minutes per stop unless a zone-level override exists, in which case the override value is used. Override is settable by operations team only."
    },
    {
      "id": "BR-8",
      "rule": "A driver operates in exactly one zone per shift.",
      "invariant": true,
      "invariant_justification": "Zone assignment is the fundamental unit of route scoping. If a driver could be in multiple zones simultaneously, route optimization becomes undefined and delivery assignment is ambiguous. This is a structural integrity constraint.",
      "testable_assertion": "For any active shift, driver.assignedZone returns exactly one zone. The system rejects attempts to assign a driver to a second zone during an active shift."
    },
    {
      "id": "BR-9",
      "rule": "Route recalculation MUST preserve the vehicle class constraint (BR-2) — no recalculation may introduce an incompatible delivery.",
      "invariant": true,
      "invariant_justification": "This is a restatement that BR-2 applies at all times, not just initial assignment. Recalculation is a frequent operation and must not be a backdoor around the safety constraint.",
      "testable_assertion": "After every route recalculation, all deliveries on the resulting route satisfy the vehicle class compatibility check."
    },
    {
      "id": "BR-10",
      "rule": "A delivery that has already been completed or is currently being delivered MUST NOT be removed or reordered by route recalculation.",
      "invariant": true,
      "invariant_justification": "Recalculating a route must not alter historical facts. A completed delivery is an immutable record. Reordering an in-progress delivery is physically impossible. Violating this corrupts delivery state.",
      "testable_assertion": "Route recalculation only modifies the sequence of future (not-yet-attempted) stops. Completed and in-progress stops remain unchanged."
    }
  ],

  "acceptance_criteria": [
    {
      "id": "AC-1",
      "given": "A driver starts their shift and is assigned to zone Z with 10 pending deliveries, all compatible with the driver's vehicle class",
      "when": "The shift is activated",
      "then": "The system generates an optimized route containing all 10 deliveries and presents it to the driver within 5 seconds"
    },
    {
      "id": "AC-2",
      "given": "A driver starts their shift in zone Z with 10 pending deliveries, 2 of which require freight vehicle class, and the driver is licensed for motorcycle only",
      "when": "The shift is activated",
      "then": "The system generates an optimized route containing only the 8 compatible deliveries; the 2 freight deliveries are NOT assigned to this driver"
    },
    {
      "id": "AC-3",
      "given": "A driver has an active route in zone Z with 5 remaining stops",
      "when": "A new delivery is created in zone Z that is compatible with the driver's vehicle class",
      "then": "The route is recalculated to include the new delivery in an optimal position among the remaining stops"
    },
    {
      "id": "AC-4",
      "given": "A driver has an active route with delivery D at stop 4 of 8",
      "when": "Delivery D is marked as failed",
      "then": "The route is recalculated with D removed and the remaining 6 stops re-optimized from the driver's current position"
    },
    {
      "id": "AC-5",
      "given": "A driver's route has stops A→B→C→D and the driver skips B and drives toward C",
      "when": "The system detects the deviation from the suggested next stop",
      "then": "The route is recalculated from the driver's current position, re-optimizing all unvisited stops (B, C, D)"
    },
    {
      "id": "AC-6",
      "given": "A driver has 6 remaining stops and a customer's delivery is at position 4",
      "when": "Route recalculation moves that customer's delivery to position 3 (entering the 'next 3 stops' window)",
      "then": "The customer receives a notification that their delivery is approaching"
    },
    {
      "id": "AC-7",
      "given": "A customer has already been notified that their delivery is in the 'next 3 stops' window",
      "when": "A route recalculation keeps the delivery within the 'next 3 stops' window",
      "then": "The customer does NOT receive a duplicate notification"
    },
    {
      "id": "AC-8",
      "given": "The operations team sets the estimated stop duration for zone Z to 6 minutes",
      "when": "A route is calculated for a driver in zone Z",
      "then": "ETA calculations use 6 minutes per stop instead of the default 4 minutes"
    },
    {
      "id": "AC-9",
      "given": "A driver has completed deliveries at stops 1 and 2 and is en route to stop 3",
      "when": "A recalculation is triggered",
      "then": "Stops 1 and 2 remain marked as completed and are not altered; only stops 3+ are re-optimized"
    },
    {
      "id": "AC-10",
      "given": "Zone Z has 15 pending deliveries but no drivers with active shifts in zone Z",
      "when": "A new delivery is added to zone Z",
      "then": "No route is generated; the delivery remains in pending state awaiting a driver to start a shift"
    },
    {
      "id": "AC-11",
      "given": "Multiple drivers have active shifts in zone Z",
      "when": "A new delivery is added to zone Z",
      "then": "The system determines which driver should receive the delivery (based on optimization criteria) and recalculates only that driver's route — OR recalculates all drivers' routes in the zone for global optimization"
    }
  ],

  "edge_cases": [
    {
      "scenario": "All pending deliveries in a zone require a vehicle class the starting driver is not licensed for",
      "expected_behavior": "The driver starts their shift with an empty route. The system should surface this to the operations team as a zone coverage gap, not silently assign incompatible deliveries."
    },
    {
      "scenario": "Multiple drivers are active in the same zone and a new delivery arrives",
      "expected_behavior": "The system must decide which driver receives the delivery. This requires a load-balancing or proximity-based assignment strategy. The spec is silent on this — requires clarification."
    },
    {
      "scenario": "A route recalculation moves a delivery OUT of the 'next 3 stops' window after the customer has already been notified",
      "expected_behavior": "The notification cannot be retracted. The customer was told their delivery is imminent but it has been deprioritized. Should the customer receive an updated ETA or apology notification? Spec is silent."
    },
    {
      "scenario": "A driver deviates from the route but returns to the original path before recalculation completes",
      "expected_behavior": "The system should detect that deviation has self-corrected and either cancel the recalculation or accept that the recalculated route may be identical to the original."
    },
    {
      "scenario": "A delivery is added to a zone at the exact moment a driver is completing their last stop",
      "expected_behavior": "Timing ambiguity: does the driver's shift end because all stops are done, or does the new delivery extend the shift? The spec does not define shift-end conditions."
    },
    {
      "scenario": "The operations team sets estimated stop duration to 0 minutes or a negative value",
      "expected_behavior": "Input validation must reject non-positive values. The stop duration represents physical time at a location and cannot be zero or negative."
    },
    {
      "scenario": "Rapid succession of recalculation triggers (e.g., 5 new deliveries added in 10 seconds)",
      "expected_behavior": "The system should debounce or batch recalculations to avoid thrashing. Each intermediate route would be immediately invalidated. Spec is silent on recalculation throttling."
    },
    {
      "scenario": "A driver's vehicle class license expires mid-shift",
      "expected_behavior": "Should the system re-validate and potentially strip incompatible deliveries mid-route? This crosses into Fleet Management policy and is not addressed."
    },
    {
      "scenario": "Deviation detection threshold is ambiguous — how far off-route triggers recalculation?",
      "expected_behavior": "The spec says 'manually deviates' but does not define the detection mechanism or threshold. GPS drift could false-trigger recalculations. Requires ops-configurable threshold."
    },
    {
      "scenario": "Customer notification delivery fails (SMS/push not delivered)",
      "expected_behavior": "The notification bounded context must handle retries and fallback channels. A failed notification should not block route progression or delivery."
    }
  ],

  "business_impact": {
    "financial": "Route optimization directly reduces fuel costs, driver hours, and cost-per-delivery. Dynamic recalculation captures new revenue from same-day/urgent deliveries inserted mid-route. However, excessive recalculation has compute cost and may cause driver confusion leading to inefficiency. Incorrect vehicle class assignment leads to failed deliveries, wasted fuel, and potential regulatory fines.",
    "operational": "Shifts from manual dispatch to algorithmic routing, reducing dispatcher workload but creating dependency on the optimization engine's availability and correctness. Operations team gains zone-level tuning via stop duration overrides. Recalculation frequency needs throttling to avoid driver fatigue from constantly changing routes. Deviation detection requires reliable GPS infrastructure.",
    "user": "Drivers receive clear, optimized routes reducing cognitive load. However, frequent recalculations may frustrate drivers who prefer route stability. Customers benefit from proactive 'next 3 stops' notifications improving delivery experience and reducing 'where is my package' inquiries. False or premature notifications (due to recalculation moving deliveries out of window) erode customer trust.",
    "risk": "HIGH: Vehicle class constraint violation is a safety and legal risk. MEDIUM: Notification promise-breaking (notified then deprioritized) damages brand trust. MEDIUM: Optimization algorithm failure or latency could leave drivers without routes. LOW: Stop duration override abuse could skew ETAs across zones. MEDIUM: Multi-driver zone assignment logic is undefined and could lead to unbalanced workloads or delivery conflicts.",
    "stakeholders_affected": [
      { "group": "Drivers", "impact": "Primary workflow change — shift from manual/dispatcher-assigned routes to automated routes. Must trust the system. Frequent recalculations may reduce trust." },
      { "group": "Customers", "impact": "Receive proactive delivery proximity notifications. Sets expectations that must be met or trust erodes." },
      { "group": "Operations Team", "impact": "Gains zone-level configuration control (stop duration). Loses some dispatch control. Needs visibility into route optimization decisions and zone coverage gaps." },
      { "group": "Dispatchers", "impact": "Role fundamentally changes from route creators to exception handlers. May resist if not included in transition planning." },
      { "group": "Finance/Management", "impact": "Expects measurable reduction in cost-per-delivery and improvement in deliveries-per-shift. Needs KPI dashboards." },
      { "group": "Compliance/Legal", "impact": "Vehicle class enforcement is a regulatory requirement. System must produce audit trail proving no violations occurred." }
    ]
  },

  "confidence": {
    "level": 55,
    "reasoning": "The spec clearly defines the core happy path and several important constraints (vehicle class, recalculation triggers, notification window, configurable stop duration). However, multiple critical operational details are unspecified: multi-driver zone behavior, deviation detection threshold, shift-end conditions, recalculation throttling, and notification retraction policy. These gaps affect real-world correctness significantly.",
    "high_confidence_areas": [
      "Vehicle class constraint is a hard invariant — safety and legal",
      "Three recalculation triggers are well-defined",
      "Customer notification at 'next 3 stops' is clear in the happy path",
      "Stop duration default and override mechanism is straightforward",
      "Single-driver-per-zone scenario is well understood"
    ],
    "low_confidence_areas": [
      "Multi-driver zone assignment strategy is completely unspecified",
      "Deviation detection mechanism and threshold are undefined",
      "Shift lifecycle (start/end conditions) is vague",
      "Notification behavior when delivery exits the 3-stop window after notification is sent",
      "Recalculation throttling/debouncing strategy",
      "What happens to unassignable deliveries (no compatible driver in zone)"
    ],
    "assumptions": [
      "A driver is assigned to exactly one zone per shift (implied but not stated explicitly)",
      "Route optimization is per-driver, not a global zone-level optimization across all drivers",
      "The 'next 3 stops' window is based on route sequence position, not geographic proximity or time",
      "Notification is sent once per delivery entering the window, not repeatedly",
      "Vehicle class compatibility is checked at assignment time and during recalculation, not continuously"
    ]
  },

  "escalations": [
    {
      "type": "ambiguity",
      "description": "Multi-driver zone behavior is undefined. When multiple drivers have active shifts in the same zone and a new delivery arrives, which driver gets it? Is this proximity-based, load-balanced, or does the system re-optimize all routes globally? This fundamentally changes the optimization architecture.",
      "affected_stakeholders": ["Drivers", "Operations Team", "Engineering"],
      "options": [
        "A: Assign to nearest driver (simple, may unbalance loads)",
        "B: Global re-optimization across all drivers in zone (complex, better outcomes)",
        "C: Assign to driver with fewest remaining stops (simple load balance)"
      ],
      "recommendation": "Option B for correctness, but start with Option C for MVP and iterate. The product team must decide."
    },
    {
      "type": "ambiguity",
      "description": "Route deviation detection threshold is undefined. 'Driver manually deviates from the suggested route' needs a precise definition — is it visiting stops out of order, exceeding a GPS distance threshold from the next stop, or missing a turn? GPS noise could cause false positives.",
      "affected_stakeholders": ["Drivers", "Engineering", "Operations Team"],
      "options": [
        "A: Deviation = driver visits a stop out of the suggested sequence",
        "B: Deviation = driver is more than X meters from the path to the next stop for Y seconds",
        "C: Both A and B"
      ],
      "recommendation": "Option A for MVP — it is deterministic and does not require GPS path-matching infrastructure. Option B can be added later with configurable thresholds."
    },
    {
      "type": "ambiguity",
      "description": "Shift lifecycle boundaries are not defined. What ends a shift — completing all stops, manual clock-out, time expiry? If a delivery arrives after all stops are done but the shift is technically active, does recalculation occur?",
      "affected_stakeholders": ["Drivers", "Operations Team", "Customers"],
      "options": [
        "A: Shift ends when driver manually clocks out",
        "B: Shift ends when all assigned stops are completed",
        "C: Shift ends on the earlier of clock-out or time limit"
      ],
      "recommendation": "Option A — driver controls their shift. Completing all stops does not auto-end the shift, allowing new deliveries to be assigned. Product team must confirm."
    },
    {
      "type": "missing_context",
      "description": "No specification of what happens when a customer notification is sent but subsequent recalculation pushes the delivery OUT of the 'next 3 stops' window. The customer has been promised imminence that is no longer true.",
      "affected_stakeholders": ["Customers", "Operations Team", "Customer Support"],
      "options": [
        "A: Send an updated ETA notification",
        "B: Do nothing — the original notification is a soft estimate",
        "C: Prevent recalculation from moving notified deliveries backward in the queue"
      ],
      "recommendation": "Option C is the most customer-friendly — once notified, the delivery becomes 'pinned' in the top 3. This prevents trust erosion. But it constrains the optimizer. Product team must weigh tradeoffs."
    }
  ],

  "rejection_reasons": []
}

